1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
13	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const CURSE_SURCHARGE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT = 0.2;
21	const LOYALTY_YEARS_THRESHOLD = 2;
22	const FOLLOWUP_DISCOUNT = 0.15;
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_INSURANCE_VALUE = 250;
27	
28	type Tariff = { base: number; insurance: number };
29	
30	const MAIN_ITEM_TARIFF: Record<string, Tariff> = {
31	  sword: { base: 100, insurance: 1000 },
32	  amulet: { base: 60, insurance: 600 },
33	};
34	
35	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_TARIFF;
38	
39	const isKnownItemType = (type: string): boolean =>
40	  type in MAIN_ITEM_TARIFF || KNOWN_COMPONENT_TYPES.has(type);
41	
42	const assertKnownItemTypes = (items: Item[]): void => {
43	  const unknown = items.find((item) => !isKnownItemType(item.type));
44	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
45	};
46	
47	const itemInsuranceValue = (item: Item): number =>
48	  MAIN_ITEM_TARIFF[item.type]?.insurance ?? COMPONENT_INSURANCE_VALUE;
49	
50	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
51	
52	const sumBy = <T>(items: T[], valueOf: (item: T) => number): number =>
53	  items.reduce((sum, item) => sum + valueOf(item), 0);
54	
55	const rateAmount = (base: number, applies: boolean, rate: number): number =>
56	  applies ? base * rate : 0;
57	
58	const enchantmentLevel = (item: Item | undefined): number => item?.enchantment ?? 0;
59	
60	const isHighlyEnchanted = (item: Item): boolean =>
61	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
62	
63	const mainItemBase = (item: Item): number => MAIN_ITEM_TARIFF[item.type].base;
64	
65	const mainItemSurcharges = (item: Item): number => {
66	  const base = mainItemBase(item);
67	  return (
68	    rateAmount(base, item.cursed === true, CURSE_SURCHARGE) +
69	    rateAmount(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE)
70	  );
71	};
72	
73	const componentGroupBase = (count: number): number => {
74	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
75	  const leftover = count % COMPONENT_BLOCK_SIZE;
76	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
77	};
78	
79	const componentCountsByType = (components: Item[]): Map<string, number> => {
80	  const counts = new Map<string, number>();
81	  for (const item of components) {
82	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
83	  }
84	  return counts;
85	};
86	
87	const sumComponentGroupBases = (components: Item[]): number =>
88	  sumBy([...componentCountsByType(components).values()], componentGroupBase);
89	
90	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => ({
91	  mainItems: items.filter(isMainItem),
92	  components: items.filter((item) => !isMainItem(item)),
93	});
94	
95	const sumMainItemBases = (mainItems: Item[]): number => sumBy(mainItems, mainItemBase);
96	
97	const sumMainItemSurcharges = (mainItems: Item[]): number => sumBy(mainItems, mainItemSurcharges);
98	
99	const isLoyalCustomer = (customer: Customer): boolean =>
100	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
101	
102	const totalDiscount = (policyBase: number, customer: Customer, isFollowUp: boolean): number =>
103	  rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT) +
104	  rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);
105	
106	const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
107	  assertKnownItemTypes(step.items);
108	  const { mainItems, components } = partitionItems(step.items);
109	  const policyBase = sumMainItemBases(mainItems) + sumComponentGroupBases(components);
110	  const surcharges = sumMainItemSurcharges(mainItems);
111	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
112	  const discounts = totalDiscount(policyBase, customer, isFollowUp);
113	  return {
114	    premium: ceilWithEpsilon(policyBase + surcharges + firstInsurance - discounts + PROCESSING_FEE),
115	  };
116	};
117	
118	const countQuotesBefore = (steps: Step[], index: number): number =>
119	  steps.slice(0, index).filter((s) => s.op === "quote").length;
120	
121	const insuranceSumOf = (step: QuoteStep): number => sumBy(step.items, itemInsuranceValue);
122	
123	const findInsuredItem = (policyStep: QuoteStep, itemType: string): Item | undefined =>
124	  policyStep.items.find((item) => item.type === itemType);
125	
126	const reimbursementRate = (item: Item | undefined): number =>
127	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
128	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
129	    : 1;
130	
131	const damagePayout = (damage: Damage, policyStep: QuoteStep): number => {
132	  const item = findInsuredItem(policyStep, damage.itemType);
133	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
134	};
135	
136	const totalPayout = (damages: Damage[], policyStep: QuoteStep): number =>
137	  sumBy(damages, (d) => damagePayout(d, policyStep));
138	
139	const initialCap = (policyStep: QuoteStep): number =>
140	  CAP_MULTIPLIER * insuranceSumOf(policyStep);
141	
142	const assertDamagesInPolicy = (damages: Damage[], policyStep: QuoteStep): void => {
143	  const orphan = damages.find((d) => !policyStep.items.some((i) => i.type === d.itemType));
144	  if (orphan) throw new Error(`Damage references item not in policy: ${orphan.itemType}`);
145	};
146	
147	const processClaim = (
148	  step: ClaimStep,
149	  steps: Step[],
150	  remainingCaps: Map<number, number>,
151	): { payout: number; remainingCap: number } => {
152	  const policyStep = steps[step.policy] as QuoteStep;
153	  assertDamagesInPolicy(step.incident.damages, policyStep);
154	  const availableCap = remainingCaps.get(step.policy) ?? initialCap(policyStep);
155	  const requestedPayout = totalPayout(step.incident.damages, policyStep);
156	  const payout = Math.min(requestedPayout, availableCap);
157	  const remainingCap = availableCap - payout;
158	  remainingCaps.set(step.policy, remainingCap);
159	  return { payout, remainingCap };
160	};
161	
162	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
163	  const remainingCaps = new Map<number, number>();
164	  return {
165	    results: scenario.steps.map((step, i) =>
166	      step.op === "quote"
167	        ? priceQuote(step, scenario.customer, countQuotesBefore(scenario.steps, i) > 0)
168	        : processClaim(step, scenario.steps, remainingCaps),
169	    ),
170	  };
171	};
